    private String mConsultarAPlicacionTto(String xidingreso) {
        String xvalor = "SIN ORDENES";
        try {
            ConsultasMySQL xct1 = new ConsultasMySQL();
            this.xsql = "SELECT  `Finalizado` FROM `h_ordenes_unidosis` WHERE (`Id_Ingreso` ='" + xidingreso + "'  AND `Finalizado` =0 AND Tipo   in(" + this.xtipoa + ")) GROUP BY `Id_Ingreso`, `Finalizado` ";
            ResultSet xrs = xct1.traerRs(this.xsql);
            if (xrs.next()) {
                xvalor = "NUEVA ORDEN";
            }
            xrs.close();
            xct1.cerrarConexionBd();
            this.xsql = "SELECT  `h_ordenes`.`Finalizada` FROM `h_ordenes`  INNER JOIN  `h_atencion`   ON (`h_ordenes`.`Id_Atencion` = `h_atencion`.`Id`) WHERE (`h_ordenes`.`Id_TipoA`    in(" + this.xtipoa + ")  AND `h_ordenes`.`Finalizada` =0 AND `h_ordenes`.`Estado` =0  AND `h_atencion`.`Id_Ingreso` ='" + xidingreso + "') GROUP BY `h_ordenes`.`Finalizada` ";
            ResultSet xrs2 = xct1.traerRs(this.xsql);
            if (xrs2.next()) {
                xvalor = "NUEVA ORDEN";
            }
            xrs2.close();
            xct1.cerrarConexionBd();
            this.xsql = "SELECT `h_tiponota`.`Orden`     FROM  `h_notasclinicas` INNER JOIN  `h_tiponota`  ON (`h_notasclinicas`.`Id_TipoNota` = `h_tiponota`.`Id`) INNER JOIN  `h_atencion`  ON (`h_notasclinicas`.`Id_Atencion` = `h_atencion`.`Id`) WHERE (`h_tiponota`.`Orden` =1 AND `h_atencion`.`Id_Ingreso` ='" + xidingreso + "') ";
            ResultSet xrs3 = xct1.traerRs(this.xsql);
            if (xrs3.next()) {
                xvalor = "NUEVA ORDEN";
            }
            xrs3.close();
            xct1.cerrarConexionBd();
        } catch (SQLException ex) {
            Logger.getLogger(JIFAgenda_UH.class.getName()).log(Level.SEVERE, (String) null, (Throwable) ex);
        }
        return xvalor;
    }

